module top_module (
    input [2:0] e,
    output reg g
);

    always @(*) begin
        case (e)
            3'b000: g = 1;
            3'b001: g = 1;
            3'b010: g = 0;
            3'b011: g = 0;
            3'b100: g = 1;
            3'b101: g = 1;
            3'b110: g = 0;
            3'b111: g = 0;
            default: g = 0; // Default case
        endcase
    end
endmodule
